function MainDialog()
this:AddTalk("<p><n color=\"255,255,0,0\">兑换提示：</n></p>");
this:AddTalk("<p><n color=\"255,255,255,0\">补 天 石：  10个碎片兑换</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">补天石灵：  50个碎片兑换</n></p>");
this:AddTalk("<p><n color=\"255,255,0,255\">补天神石： 250个碎片兑换</n></p>");
this:AddTalk("<p><n color=\"255,255,100,0\">补天仙石：1250个碎片兑换</n></p>");

this:AddTaskCmdItem("领取补 天 石(0)", "u50000", 114311, 99)
this:AddTaskCmdItem("领取补天灵石(0)", "u50000", 114311, 99)
this:AddTaskCmdItem("领取补天神石(0)", "u50000", 114311, 99)
this:AddTaskCmdItem("领取补天仙石(0)", "u50000", 114311, 99)

this:AddCloseItem("离开")
end
function MoveCanClose()
return false
end
this:AddDialog("MainDialog")

